function makeFlagKey(toolKey: string, featureKey: string) {
  const t = toolKey.trim().toLowerCase();
  const f = featureKey.trim().toLowerCase();
  return `${t}.${f}`;
}
// uso: makeFlagKey('academy','newOnboarding') => 'academy.newonboarding'

const FLAG_REGEX = /^[a-z0-9-_]+\.[a-z0-9-_]+$/;
function validateFlagKey(key: string) {
  return FLAG_REGEX.test(key) && key.length <= 64;
}
